// ============================================================================
// CONFIGURACIÓN DE LA API
// ============================================================================

const API_BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";
class ApiError extends Error {
  constructor(status, message) {
    super(message);
    this.status = status;
    this.name = "ApiError";
  }
}

// ============================================================================
// FUNCIONES HELPER PARA REQUESTS
// ============================================================================

async function apiRequest(endpoint, options = {}) {
  const url = `${API_BASE_URL}${endpoint}`;

  // Obtener token del localStorage si existe
  const token = localStorage.getItem("token");
  const defaultHeaders = {
    "Content-Type": "application/json",
    Accept: "application/json",
    ...(token && {
      Authorization: `Bearer ${token}`
    })
  };
  const config = {
    ...options,
    headers: {
      ...defaultHeaders,
      ...options.headers
    }
  };
  try {
    const response = await fetch(url, config);
    if (!response.ok) {
      throw new ApiError(response.status, `HTTP error! status: ${response.status}`);
    }

    // Verificar si la respuesta tiene contenido antes de parsear JSON
    const contentType = response.headers.get("content-type");
    const hasJsonContent = contentType && contentType.includes("application/json");

    // Si no hay contenido (como en DELETE) o no es JSON, devolver respuesta vacía
    if (response.status === 204 || !hasJsonContent) {
      return {};
    }

    // Verificar si hay contenido en el body
    const text = await response.text();
    if (!text || text.trim() === "") {
      return {};
    }

    // Parsear JSON solo si hay contenido
    const data = JSON.parse(text);
    return data;
  } catch (error) {
    console.error("API Request Error:", error);
    throw error;
  }
}

