export interface Mesa {
  id: number;
  numero: number;
  estado: "LIBRE" | "OCUPADA" | "RESERVADA";
  capacidad?: number;
  ubicacion?: string;
  fechaCreacion?: string;
  fechaActualizacion?: string;
}

export interface MesaCreateRequest {
  numero: number;
  estado?: "LIBRE" | "OCUPADA" | "RESERVADA";
  capacidad?: number;
  ubicacion?: string;
}

export interface MesaUpdateRequest extends Partial<MesaCreateRequest> {}

export interface ApiResponse<T> {
  success: boolean;
  data: T;
  message?: string;
  error?: string;
}

// ============================================================================
// CONFIGURACIÓN DE LA API
// ============================================================================

const API_BASE_URL =
  process.env.REACT_APP_API_URL || "http://localhost:8080/api";

class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = "ApiError";
  }
}

// ============================================================================
// FUNCIONES HELPER PARA REQUESTS
// ============================================================================

async function apiRequest<T>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> {
  const url = `${API_BASE_URL}${endpoint}`;

  // Obtener token del localStorage si existe
  const token = localStorage.getItem("token");

  const defaultHeaders = {
    "Content-Type": "application/json",
    Accept: "application/json",
    ...(token && { Authorization: `Bearer ${token}` }),
  };

  const config: RequestInit = {
    ...options,
    headers: { ...defaultHeaders, ...options.headers },
  };

  try {
    const response = await fetch(url, config);

    if (!response.ok) {
      throw new ApiError(
        response.status,
        `HTTP error! status: ${response.status}`
      );
    }

    // Verificar si la respuesta tiene contenido antes de parsear JSON
    const contentType = response.headers.get("content-type");
    const hasJsonContent =
      contentType && contentType.includes("application/json");

    // Si no hay contenido (como en DELETE) o no es JSON, devolver respuesta vacía
    if (response.status === 204 || !hasJsonContent) {
      return {} as T;
    }

    // Verificar si hay contenido en el body
    const text = await response.text();
    if (!text || text.trim() === "") {
      return {} as T;
    }

    // Parsear JSON solo si hay contenido
    const data = JSON.parse(text);
    return data;
  } catch (error) {
    console.error("API Request Error:", error);
    throw error;
  }
}

// ============================================================================
// SERVICIOS DE MESAS
// ============================================================================

/**
 * Obtiene todas las mesas desde la base de datos
 */
export async function getMesas(): Promise<Mesa[]> {
  try {
    const response = await apiRequest<Mesa[]>("/mesas");
    return response;
  } catch (error) {
    console.warn("Backend no disponible, usando datos mock:", error);

    // Simular delay de red
    await new Promise((resolve) => setTimeout(resolve, 500));
    return [...mesasMockData];
  }
}

/**
 * Obtiene una mesa específica por ID
 */
export async function getMesaPorId(id: number): Promise<Mesa> {
  try {
    const response = await apiRequest<Mesa>(`/mesas/${id}`);
    return response;
  } catch (error) {
    console.error(`Error al obtener mesa ${id}:`, error);
    throw new Error(`No se pudo cargar la mesa con ID ${id}`);
  }
}

/**
 * Crea una nueva mesa en la base de datos
 */
export async function agregarMesa(mesa: MesaCreateRequest): Promise<Mesa> {
  try {
    // Validaciones básicas
    if (!mesa.numero || mesa.numero <= 0) {
      throw new Error("El número de mesa debe ser mayor a 0");
    }

    const response = await apiRequest<Mesa>("/mesas", {
      method: "POST",
      body: JSON.stringify({
        numero: mesa.numero,
        estado: mesa.estado || "LIBRE",
        capacidad: mesa.capacidad || 4,
        ubicacion: mesa.ubicacion || "Salón principal",
      }),
    });

    return response;
  } catch (error) {
    console.warn(
      "Backend no disponible, usando mock para agregar mesa:",
      error
    );

    // Verificar si ya existe el número de mesa en mock
    if (mesasMockData.some((m) => m.numero === mesa.numero)) {
      throw new Error("Ya existe una mesa con ese número");
    }

    // Crear nueva mesa en mock
    const nuevaMesa: Mesa = {
      id: Math.max(...mesasMockData.map((m) => m.id), 0) + 1,
      numero: mesa.numero,
      estado: mesa.estado || "LIBRE",
      capacidad: mesa.capacidad || 4,
      ubicacion: mesa.ubicacion || "Salón principal",
      fechaCreacion: new Date().toISOString(),
    };

    mesasMockData.push(nuevaMesa);

    // Simular delay de red
    await new Promise((resolve) => setTimeout(resolve, 500));
    return nuevaMesa;
  }
}

/**
 * Actualiza una mesa existente
 */
export async function editarMesa(
  id: number,
  mesa: MesaUpdateRequest
): Promise<Mesa> {
  try {
    if (!id || id <= 0) {
      throw new Error("ID de mesa inválido");
    }

    const response = await apiRequest<Mesa>(`/mesas/${id}`, {
      method: "PUT",
      body: JSON.stringify(mesa),
    });

    return response;
  } catch (error) {
    console.warn("Backend no disponible, usando mock para editar mesa:", error);

    const index = mesasMockData.findIndex((m) => m.id === id);
    if (index === -1) {
      throw new Error("Mesa no encontrada");
    }

    // Actualizar mesa en mock
    mesasMockData[index] = {
      ...mesasMockData[index],
      ...mesa,
      fechaActualizacion: new Date().toISOString(),
    };

    // Simular delay de red
    await new Promise((resolve) => setTimeout(resolve, 300));
    return mesasMockData[index];
  }
}

/**
 * Elimina una mesa de la base de datos
 */
export async function eliminarMesa(id: number): Promise<void> {
  console.log(`Servicio: Eliminando mesa con ID: ${id}`);
  
  try {
    if (!id || id <= 0) {
      throw new Error("ID de mesa inválido");
    }

    // Intentar con API real primero
    await apiRequest<void>(`/mesas/${id}`, {
      method: "DELETE",
    });
    
    console.log(`Mesa ${id} eliminada exitosamente del backend`);
    
    // Si llegamos aquí, la eliminación fue exitosa
    // También eliminar del mock para mantener consistencia
    const mockIndex = mesasMockData.findIndex((mesa) => mesa.id === id);
    if (mockIndex !== -1) {
      mesasMockData.splice(mockIndex, 1);
      console.log(`Mesa ${id} también eliminada del mock data`);
    }
    
    return;
    
  } catch (error) {
    console.warn(
      "Error en backend, intentando con mock data:",
      error
    );

    // Fallback: eliminar del mock
    const index = mesasMockData.findIndex((mesa) => mesa.id === id);
    console.log(`Buscando mesa ${id} en mock data. Índice encontrado: ${index}`);
    console.log(`Mock data actual:`, mesasMockData);
    
    if (index === -1) {
      // Si no está en mock, puede que la mesa venga del backend
      // Intentar recargar las mesas y mostrar un error más específico
      console.error(`Mesa con ID ${id} no encontrada en mock data`);
      throw new Error(`Mesa con ID ${id} no encontrada. Puede que ya haya sido eliminada.`);
    }

    const mesaEliminada = mesasMockData[index];
    mesasMockData.splice(index, 1);
    console.log(`Mesa eliminada del mock:`, mesaEliminada);

    // Simular delay de red
    await new Promise((resolve) => setTimeout(resolve, 300));
  }
}

/**
 * Cambia el estado de una mesa
 */
export async function cambiarEstadoMesa(
  id: number,
  nuevoEstado: Mesa["estado"]
): Promise<Mesa> {
  try {
    return await editarMesa(id, { estado: nuevoEstado });
  } catch (error) {
    console.error(`Error al cambiar estado de mesa ${id}:`, error);
    throw new Error("No se pudo cambiar el estado de la mesa");
  }
}

/**
 * Obtiene mesas filtradas por estado
 */
export async function getMesasPorEstado(
  estado: Mesa["estado"]
): Promise<Mesa[]> {
  try {
    const response = await apiRequest<Mesa[]>(`/mesas?estado=${estado}`);
    return response;
  } catch (error) {
    console.error(`Error al obtener mesas con estado ${estado}:`, error);
    throw new Error(`No se pudieron cargar las mesas ${estado.toLowerCase()}s`);
  }
}

/**
 * Verifica si el servicio de mesas está disponible
 */
export async function verificarConexion(): Promise<boolean> {
  try {
    await apiRequest<any>("/mesas/health");
    return true;
  } catch (error) {
    console.warn("Servicio de mesas no disponible:", error);
    return false;
  }
}

// ============================================================================
// FUNCIONES DE UTILIDAD
// ============================================================================

/**
 * Valida los datos de una mesa antes de enviarlos
 */
export function validarMesa(mesa: MesaCreateRequest): string[] {
  const errores: string[] = [];

  if (!mesa.numero || mesa.numero <= 0) {
    errores.push("El número de mesa debe ser mayor a 0");
  }

  if (mesa.capacidad && mesa.capacidad <= 0) {
    errores.push("La capacidad debe ser mayor a 0");
  }

  if (mesa.estado && !["LIBRE", "OCUPADA", "RESERVADA"].includes(mesa.estado)) {
    errores.push("Estado inválido");
  }

  return errores;
}

/**
 * Formatea el estado para mostrar
 */
export function formatearEstado(estado: Mesa["estado"]): string {
  const estados = {
    LIBRE: "Libre",
    OCUPADA: "Ocupada",
    RESERVADA: "Reservada",
  };
  return estados[estado] || estado;
}

/**
 * Obtiene el color asociado al estado
 */
export function obtenerColorEstado(estado: Mesa["estado"]): string {
  const colores = {
    LIBRE: "green",
    OCUPADA: "red",
    RESERVADA: "yellow",
  };
  return colores[estado] || "gray";
}

// ============================================================================
// MOCK DATA PARA DESARROLLO (REMOVER EN PRODUCCIÓN)
// ============================================================================

const MOCK_MESAS: Mesa[] = [
  {
    id: 1,
    numero: 1,
    estado: "LIBRE",
    capacidad: 4,
    ubicacion: "Salón principal",
    fechaCreacion: new Date().toISOString(),
  },
  {
    id: 2,
    numero: 2,
    estado: "OCUPADA",
    capacidad: 2,
    ubicacion: "Terraza",
    fechaCreacion: new Date().toISOString(),
  },
  {
    id: 3,
    numero: 3,
    estado: "RESERVADA",
    capacidad: 6,
    ubicacion: "Salón VIP",
    fechaCreacion: new Date().toISOString(),
  },
];

let mesasMockData = [...MOCK_MESAS];

/**
 * Función para usar datos mock cuando el backend no esté disponible
 */
export async function getMesasMock(): Promise<Mesa[]> {
  // Simular delay de red
  await new Promise((resolve) => setTimeout(resolve, 500));
  return [...MOCK_MESAS];
}
